blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE)
container = database.create_container_if_not_exists(
    id=COSMOS_CONTAINER,
    partition_key=PartitionKey(path="/partitionKey"),
)


def _parse_blob_trigger_path(invocation_path: str) -> Dict[str, str]:
    parts = invocation_path.strip("/").split("/", 1)
    if len(parts) != 2:
        raise ValueError(f"Invalid blob path: {invocation_path}")
    return {"container": parts[0], "blob_name": parts[1]}


def _read_blob_text(container_name: str, blob_name: str) -> str:
    blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
    return blob_client.download_blob().readall().decode("utf-8")


def _process_content(content: str, blob_name: str) -> Dict[str, Any]:
    lines = content.splitlines()
    words = content.split()
    return {
        "id": blob_name.replace("/", "_"),
        "partitionKey": "processed-files",
        "blobName": blob_name,
        "lineCount": len(lines),
        "wordCount": len(words),
        "charCount": len(content),
        "status": "processed",
    }


def _write_to_cosmos(document: Dict[str, Any]) -> None:
    container.upsert_item(document)


